                        items?: {
                            length: number;
                            at?: (index: number) => { id: string; } | undefined;
                            [index: number]: { id: string; };
                        };
                    };
                };
            }).generalStore;
            if (gs?.currentPage) {
                const items = gs.currentPage.items;
                if (items && items.length > 0) {
                    const lastItem = items.at ? items.at(items.length - 1) : items[items.length - 1];
