// Minimal Yjs-branch snapshot saver used by E2E tests
// Produces JSON files under client/e2e-snapshots named <label>-yjs.json

import type { Page, TestInfo } from "@playwright/test";

export class DataValidationHelpers {
    /**
     * Convenience helper to be called from test.afterEach to persist a Yjs snapshot.
     * Builds a stable label from the test title and appends -auto-<timestamp>.
     * Swallows errors by design so it never fails the test teardown.
     */
    static async trySaveAfterEach(page: Page, testInfo: TestInfo): Promise<void> {
        try {
            // Check if page is still open before trying to save
            if (page.isClosed()) {
                console.log("[afterEach] Page already closed, skipping snapshot save");
                return;
            }

            const labelBase = testInfo.title.replace(/[^a-z0-9_-]+/gi, "-");
            const label = `${labelBase}-auto-${Date.now()}`;
            await DataValidationHelpers.saveSnapshotsAndCompare(page, label);
        } catch (e: any) {
            // Do not fail the test if snapshot saving fails
            console.warn("[afterEach] snapshot skipped:", e?.message ?? e);
        } finally {
            try {
                // Check if page is still open before trying to dump logs
                if (!page.isClosed()) {
                    // Dump E2E logs if present
                    const logs = await page.evaluate(() => {
                        const w: any = window as any;
                        return Array.isArray(w.E2E_LOGS) ? w.E2E_LOGS.slice(-200) : [];
                    }, { timeout: 2000 });
                    if (Array.isArray(logs) && logs.length) {
                        console.log("[afterEach] E2E_LOGS (last 200):", logs);
                    }
                } else {
                    console.log("[afterEach] Page already closed, skipping log dump");
                }
            } catch (e) {
                console.warn("[afterEach] log dump skipped:", e?.message ?? e);
            }
        }
    }

    /**
     * Cleanup helper to be called from test.afterEach to ensure test isolation.
     * Resets Yjs state and other global state between tests.
     * Swallows errors by design so it never fails the test teardown.
     */
    static async tryCleanupAfterEach(page: Page): Promise<void> {
        try {
            // Check if page is still open before trying to evaluate
            if (page.isClosed()) {
                console.log("[afterEach] Page already closed, skipping cleanup");
                return;
            }

            // Reset Yjs state and other global variables between tests
            // Use a shorter timeout for cleanup to avoid hanging
            await page.evaluate(() => {
                try {
                    // Clear any existing E2E logs
                    const w: any = window as any;
                    if (Array.isArray(w.E2E_LOGS)) {
                        w.E2E_LOGS.length = 0;
                    }

                    // Reset global state that might affect test isolation
                    if (w.generalStore) {
                        // Reset comment-related state
                        if (w.generalStore.openCommentItemId) {
                            w.generalStore.openCommentItemId = null;
                        }
                        if (w.generalStore.openCommentItemIndex) {
                            w.generalStore.openCommentItemIndex = null;
                        }
                    }

                    // Clear any editor overlay state
                    if (w.editorOverlayStore) {
                        try {
                            // Reset cursor state
                            if (w.editorOverlayStore.reset) {
                                w.editorOverlayStore.reset();
                            } else {
                                // Manually clear if no reset method
                                w.editorOverlayStore.cursors = {};
                                w.editorOverlayStore.selections = {};
                                w.editorOverlayStore.activeItemId = null;
                                w.editorOverlayStore.cursorVisible = false;
                                if (w.editorOverlayStore.cursorInstances) {
                                    w.editorOverlayStore.cursorInstances.clear();
                                }
                            }
                        } catch {}
                    }

                    // Clear any alias picker state
                    if (w.aliasPickerStore) {
                        try {
                            if (w.aliasPickerStore.reset) {
                                w.aliasPickerStore.reset();
                            } else {
                                w.aliasPickerStore.isVisible = false;
                                w.aliasPickerStore.selectedOptionId = null;
                                w.aliasPickerStore.query = "";
                            }
                        } catch {}
                    }

                    // Clear any command palette state
                    if (w.commandPaletteStore) {
                        try {
                            if (w.commandPaletteStore.reset) {
                                w.commandPaletteStore.reset();
                            } else {
                                w.commandPaletteStore.isVisible = false;
                                w.commandPaletteStore.query = "";
                            }
                        } catch {}
                    }

                    // Clear any user preferences
                    if (w.userPreferencesStore) {
                        try {
                            if (w.userPreferencesStore.reset) {
                                w.userPreferencesStore.reset();
                            }
                        } catch {}
                    }

                    // Clear search history
                    if (w.searchHistoryStore) {
                        try {
                            if (w.searchHistoryStore.reset) {
                                w.searchHistoryStore.reset();
                            }
                        } catch {}
                    }
                } catch (e) {
                    console.warn("[afterEach] cleanup warning:", e);
                }
            }, { timeout: 5000 }).catch((e) => {
                // Ignore errors during cleanup evaluation
                console.log("[afterEach] cleanup evaluation skipped:", e?.message ?? e);
            });
        } catch (e: any) {
            // Do not fail the test if cleanup fails
            console.warn("[afterEach] cleanup skipped:", e?.message ?? e);
        }
    }

    static async saveSnapshotsAndCompare(page: Page, label: string = "default"): Promise<void> {
        // Check if page is still open before trying to access project
        if (page.isClosed()) {
            console.log("[saveSnapshotsAndCompare] Page already closed, skipping snapshot");
            return;
        }

        // Wait for the project to be available in the store
        try {
            await page.waitForFunction(() => {
                const store = (window as any).generalStore || (window as any).appStore;
                return !!(store && store.project);
            }, { timeout: 30000 });
        } catch (e) {
            console.warn("[saveSnapshotsAndCompare] waitForFunction failed:", e?.message ?? e);
            return; // Skip snapshot if project is not available
        }

        // Check again if page is still open before evaluating
        if (page.isClosed()) {
            console.log("[saveSnapshotsAndCompare] Page already closed, skipping snapshot");
            return;
        }

        // Build a minimal snapshot directly from the app store on the page
        let result;
        try {
            result = await page.evaluate(async () => {
                function yTextToString(t: any): string {
                    if (!t) return "";
                    try {
                        return typeof t.toString === "function" ? t.toString() : String(t);
                    } catch {
                        return String(t);
                    }
                }

                const store = (window as any).generalStore || (window as any).appStore;
                if (!store || !store.project) {
                    throw new Error("Project not available on window.generalStore/appStore");
                }

                const project = store.project;
                const pages: Array<{ title: string; items: Array<{ text: string; }>; }> = [];

                // project.items is proxied array-like; iterate by length
                const len = (project.items as any)?.length ?? 0;
                for (let i = 0; i < len; i++) {
                    const pageItem = (project.items as any).at(i);
                    if (!pageItem) continue;
                    const pageTitle = yTextToString(pageItem.text);
                    const children: Array<{ text: string; }> = [];
                    const clen = (pageItem.items as any)?.length ?? 0;
                    for (let j = 0; j < clen; j++) {
                        const child = (pageItem.items as any).at(j);
                        if (!child) continue;
                        children.push({ text: yTextToString(child.text) });
                    }
                    // First item is the page title by convention (legacy snapshotter alignment)
                    pages.push({ title: pageTitle, items: [{ text: pageTitle }, ...children] });
                }

                return {
                    mode: "yjs",
                    yjsJson: JSON.stringify({ projectTitle: String(project.title ?? ""), pages }, null, 2),
                };
            }, { timeout: 30000 });
        } catch (e) {
            console.warn("[saveSnapshotsAndCompare] evaluate failed:", e?.message ?? e);
            return; // Skip snapshot if evaluation fails
        }

        const path = await import("path");
        const fsPromises = await import("fs/promises");
        // Write snapshots in the client directory to match test expectations
        const outDir = path.resolve(process.cwd(), "e2e-snapshots");
        await fsPromises.mkdir(outDir, { recursive: true }).catch(() => {});
        const yjsPath = path.join(outDir, `${label}-yjs.json`);
        if (!result.yjsJson) throw new Error("Yjs snapshot missing");
        await fsPromises.writeFile(yjsPath, result.yjsJson);
        console.log(`Saved Yjs snapshot: ${yjsPath}`);
    }
}

import type { Page } from "@playwright/test";
import { expect } from "@playwright/test";

import { TestHelpers } from "./testHelpers";

/**
 * Helper functions for internal link testing (Yjs based)
 */
export class LinkTestHelpers {
    /**
     * Create a test project and page
     * @param page Playwright page object
     * @param projectName Project name
     * @param pageName Page name
     * @param content Page content (optional)
     */
    static async createTestProjectAndPage(
        page: Page,
        projectName: string,
        pageName: string,
        content: string[] = ["This is a test page.", "Internal link test: [test-link]"],
    ): Promise<void> {
        // Setup tree debugger
        await TestHelpers.setupTreeDebugger(page);

        // Wait for Yjs backing store initialization
        await page.waitForFunction(() => {
            const gs: any = (window as any).generalStore || (window as any).appStore;
            return !!(gs && gs.project);
        }, { timeout: 30000 });

        // Create via Yjs API
        await page.evaluate(({ projectName, pageName, content }) => {
            const gs: any = (window as any).generalStore || (window as any).appStore;
            if (!gs?.project) throw new Error("generalStore.project not ready");

            try {
                gs.project.title = projectName;

                const pages: any = gs.project.items;
                const len = pages?.length ?? 0;
                let target: any = undefined;
                for (let i = 0; i < len; i++) {
                    const it = pages.at ? pages.at(i) : pages[i];
                    const t = it?.text?.toString?.() ?? String(it?.text ?? "");
                    if (String(t) === pageName) {
                        target = it;
                        break;
                    }
                }

                if (!target) target = gs.project.addPage(pageName, "tester");
                else target.updateText(pageName);

                const items = target.items as any;
                while ((items?.length ?? 0) > 0) items.removeAt(0);
                for (const line of content) {
                    const it = items.addNode("tester");
                    it.updateText(line);
                }
                if (!gs.currentPage) gs.currentPage = target;
            } catch (e) {
                console.error("Error creating project/page via Yjs:", e);
                throw e;
            }
        }, { projectName, pageName, content });

        await page.waitForTimeout(200);
    }

    /**
     * Create multiple projects and pages
     * @param page Playwright page object
     * @param projects Projects and pages information
     */
    static async createMultipleProjectsAndPages(
        page: Page,
        projects: Array<{
            projectName: string;
            pages: Array<{
                pageName: string;
                content?: string[];
            }>;
        }>,
    ): Promise<void> {
        // Setup tree debugger
        await TestHelpers.setupTreeDebugger(page);

        // Wait for Yjs initialization
        await page.waitForFunction(() => {
            const gs: any = (window as any).generalStore || (window as any).appStore;
            return !!(gs && gs.project);
        }, { timeout: 30000 });

        // Prepare multiple pages in a single project
        await page.evaluate((projects) => {
            const gs: any = (window as any).generalStore || (window as any).appStore;
            if (!gs?.project) throw new Error("generalStore.project not ready");
            try {
                if (projects.length > 0) gs.project.title = projects[0].projectName;
                for (const p of projects) {
                    for (const pg of p.pages) {
                        const pages: any = gs.project.items;
                        const len = pages?.length ?? 0;
                        let target: any = undefined;
                        for (let i = 0; i < len; i++) {
                            const it = pages.at ? pages.at(i) : pages[i];
                            const t = it?.text?.toString?.() ?? String(it?.text ?? "");
                            if (String(t) === pg.pageName) {
                                target = it;
                                break;
                            }
                        }
                        if (!target) target = gs.project.addPage(pg.pageName, "tester");
                        const items = target.items as any;
                        while ((items?.length ?? 0) > 0) items.removeAt(0);
                        const lines = pg.content || ["This is a test page.", "Internal link test: [test-link]"];
                        for (const line of lines) {
                            const it = items.addNode("tester");
                            it.updateText(line);
                        }
                    }
                }
            } catch (e) {
                console.error("Error creating pages via Yjs:", e);
                throw e;
            }
        }, projects);

        await page.waitForTimeout(200);
    }

    /**
     * Test internal link navigation functionality
     * @param page Playwright page object
     * @param linkSelector Internal link selector
     * @param expectedUrl Expected URL
     */
    static async testInternalLinkNavigation(
        page: Page,
        linkSelector: string,
        expectedUrl: string,
    ): Promise<void> {
        // Save current URL
        const currentUrl = page.url();

        // Click the link
        await page.click(linkSelector);

        // Wait for page to load
        await page.waitForSelector("body", { timeout: 10000 });

        // Get new URL
        const newUrl = page.url();

        // Verify URL is as expected
        expect(newUrl).toContain(expectedUrl);

        // Verify URL has changed
        expect(newUrl).not.toBe(currentUrl);
    }

    /**
     * Create test page directly (using Yjs API instead of UI operation)
     * @param page Playwright page object
     * @param projectName Project name
     * @param pageName Page name
     * @param content Page content (multiple lines array)
     * @param navigateToPage Whether to navigate to page after creation
     */
    static async createTestPageDirect(
        page: Page,
        projectName: string,
        pageName: string,
        content: string[] = ["This is the content of the test page."],
        navigateToPage: boolean = false,
    ): Promise<void> {
        // Setup tree debugger
        await TestHelpers.setupTreeDebugger(page);

        // Wait for Yjs initialization
        await page.waitForFunction(() => {
            const gs: any = (window as any).generalStore || (window as any).appStore;
            return !!(gs && gs.project);
        }, { timeout: 30000 });

        await page.evaluate(({ projectName, pageName, content }) => {
            const gs: any = (window as any).generalStore || (window as any).appStore;
            if (!gs?.project) throw new Error("generalStore.project not ready");
            try {
                gs.project.title = projectName;
                const pages: any = gs.project.items;
                const len = pages?.length ?? 0;
                let target: any = undefined;
                for (let i = 0; i < len; i++) {
                    const it = pages.at ? pages.at(i) : pages[i];
                    const t = it?.text?.toString?.() ?? String(it?.text ?? "");
                    if (String(t) === pageName) {
                        target = it;
                        break;
                    }
                }
                if (!target) target = gs.project.addPage(pageName, "tester");
                const items = target.items as any;
                while ((items?.length ?? 0) > 0) items.removeAt(0);
                for (const line of content) {
                    const it = items.addNode("tester");
                    it.updateText(line);
                }
                if (!gs.currentPage) gs.currentPage = target;
            } catch (e) {
                console.error("Error creating page via Yjs:", e);
                throw e;
            }
        }, { projectName, pageName, content });

        if (navigateToPage) {
            await page.goto(`/${projectName}/${pageName}`);
            await page.waitForSelector(".outliner-item", { timeout: 10000 });
        }
    }

    /**
     * Open an existing page
     * @param page Playwright page object
     * @param projectName Project name
     * @param pageName Page name
     */
    static async openPage(
        page: Page,
        projectName: string,
        pageName: string,
    ): Promise<void> {
        // Navigate to page
        await page.goto(`/${projectName}/${pageName}`);

        // Wait for page to load
        await page.waitForSelector(".outliner-item", { timeout: 10000 });

        // Click developer login button (if visible)
        const loginButton = page.locator("button:has-text('Developer Login')");
        if (await loginButton.isVisible()) {
            await loginButton.click();
            await page.waitForTimeout(1000);
        }
    }

    /**
     * Force create an internal link
     * @param page Playwright page object
     * @param itemId Item ID
     * @param linkText Link text
     */
    static async forceCreateInternalLink(page: Page, itemId: string, linkText: string): Promise<void> {
        await page.evaluate(({ itemId, linkText }) => {
            const gs: any = (window as any).generalStore || (window as any).appStore;
            if (!gs?.project) return false;
            try {
                const findById = (parent: any): any => {
                    if (!parent) return null;
                    const items: any = parent.items;
                    const len = items?.length ?? 0;
                    for (let i = 0; i < len; i++) {
                        const it = items.at ? items.at(i) : items[i];
                        if (!it) continue;
                        if (String(it.id) === String(itemId)) return it;
                        const found = findById(it);
                        if (found) return found;
                    }
                    return null;
                };

                // Search from root (page list)
                const pages: any = gs.project.items;
                const plen = pages?.length ?? 0;
                let target: any = null;
                for (let i = 0; i < plen; i++) {
                    const p = pages.at ? pages.at(i) : pages[i];
                    if (String(p?.id) === String(itemId)) {
                        target = p;
                        break;
                    }
                    const found = findById(p);
                    if (found) {
                        target = found;
                        break;
                    }
                }
                if (!target) return false;

                const currentText = target?.text?.toString?.() ?? String(target?.text ?? "");
                const newText = `${currentText} [${linkText}]`;
                target.updateText(newText);
                return true;
            } catch (e) {
                console.error("Error creating internal link (Yjs):", e);
                return false;
            }
        }, { itemId, linkText });

        await page.waitForTimeout(200);
    }

    /**
     * Detect internal link
     * @param page Playwright page object
     * @param linkText Link text
     * @returns True if link element exists
     */
    static async detectInternalLink(page: Page, linkText: string): Promise<boolean> {
        // Detect link element
        const linkCount = await page.evaluate(text => {
            const links = Array.from(document.querySelectorAll("a.internal-link")).filter(
                el => el.textContent === text,
            );
            return links.length;
        }, linkText);

        return linkCount > 0;
    }

    /**
     * Force show internal link preview
     * @param page Playwright page object
     * @param pageName Page name to show preview for
     * @param projectName Project name (optional)
     * @param pageExists Whether page exists (default true)
     */
    static async forceLinkPreview(
        page: Page,
        pageName: string,
        projectName?: string,
        pageExists: boolean = true,
    ): Promise<void> {
        await page.evaluate(({ pageName, projectName, pageExists }) => {
            // Create global function if not exists
            if (!window.__testShowLinkPreview) {
                window.__testShowLinkPreview = (pageName, projectName, pageExists) => {
                    console.log(`Forcing link preview for page: ${pageName} (exists: ${pageExists})`);

                    // Create preview popup
                    let popup = document.querySelector(".link-preview-popup");
                    if (!popup) {
                        popup = document.createElement("div");
                        popup.className = "link-preview-popup";
                        document.body.appendChild(popup);
                    }

                    // Set preview content
                    if (pageExists) {
                        // If page exists
                        popup.innerHTML = `
                            <h3>${pageName}</h3>
                            <div class="preview-items">
                                <p>This is test preview content.</p>
                            </div>
                        `;
                    } else {
                        // If page does not exist
                        popup.innerHTML = `
                            <h3>${pageName}</h3>
                            <div class="preview-not-found">
                                <p>Page not found. Click to create new.</p>
                            </div>
                        `;
                    }

                    // Set styles and show
                    (popup as HTMLElement).style.display = "block";
                    (popup as HTMLElement).style.position = "fixed";
                    (popup as HTMLElement).style.top = "100px";
                    (popup as HTMLElement).style.left = "100px";
                    (popup as HTMLElement).style.zIndex = "1000";
                    (popup as HTMLElement).style.backgroundColor = "#fff";
                    (popup as HTMLElement).style.border = "1px solid #ccc";
                    (popup as HTMLElement).style.padding = "10px";
                    (popup as HTMLElement).style.boxShadow = "0 2px 5px rgba(0,0,0,0.2)";

                    return popup as HTMLElement;
                };
            }

            // Show preview
            return window.__testShowLinkPreview(pageName, projectName, pageExists);
        }, { pageName, projectName, pageExists });

        // Wait for preview to appear
        await page.waitForTimeout(500);
    }

    /**
     * Force render internal links
     * @param page Playwright page object
     */
    static async forceRenderInternalLinks(page: Page): Promise<void> {
        const result = await page.evaluate(() => {
            // Get all outliner items
            const items = document.querySelectorAll(".outliner-item");
            console.log(`Found ${items.length} outliner items`);

            let linksFound = 0;
            let linksProcessed = 0;

            // Re-render text of each item
            items.forEach(item => {
                const textElement = item.querySelector(".item-text");
                if (textElement) {
                    // Get text content
                    const text = textElement.textContent || "";

                    // Detect internal link pattern (normal internal link)
                    const linkPattern = /\[([^[\]/-][^[\]]*?)\]/g;
                    // Detect project internal link pattern
                    const projectLinkPattern = /\[\/([\w\-/]+)\]/g;

                    const hasNormalLinks = linkPattern.test(text);
                    // Reset lastIndex after testing
                    linkPattern.lastIndex = 0;

                    const hasProjectLinks = projectLinkPattern.test(text);
                    // Reset lastIndex after testing
                    projectLinkPattern.lastIndex = 0;

                    if (hasNormalLinks || hasProjectLinks) {
                        linksFound++;

                        // Set HTML directly if link exists
                        let html = text;

                        // Process normal internal link
                        if (hasNormalLinks) {
                            html = html.replace(linkPattern, (match, linkText) => {
                                linksProcessed++;
                                return `<span class="link-preview-wrapper">
                                    <a href="/${linkText}" class="internal-link" data-page="${linkText}">${linkText}</a>
                                </span>`;
                            });
                        }

                        // Process project internal link
                        if (hasProjectLinks) {
                            html = html.replace(projectLinkPattern, (match, path) => {
                                linksProcessed++;
                                // Split path to get project name and page name
                                const parts = path.split("/").filter(p => p);
                                if (parts.length >= 2) {
                                    const projectName = parts[0];
                                    const pageName = parts.slice(1).join("/");

                                    return `<span class="link-preview-wrapper">
                                        <a href="/${path}" class="internal-link project-link" data-project="${projectName}" data-page="${pageName}">${path}</a>
                                    </span>`;
                                } else {
                                    return `<a href="/${path}" class="internal-link project-link">${path}</a>`;
                                }
                            });
                        }

                        // Set HTML
                        textElement.innerHTML = html;

                        // Add formatted class
                        textElement.classList.add("formatted");
                    }
                }
            });

            // Set event listeners on links
            const setupLinkEventListeners = () => {
                const links = document.querySelectorAll("a.internal-link");
                console.log(`Found ${links.length} internal links to setup event listeners`);

                links.forEach(link => {
                    // Flag to check if already set
                    const hasListeners = link.getAttribute("data-link-listeners") === "true";

                    if (!hasListeners) {
                        // Add mouseenter event listener
                        link.addEventListener("mouseenter", () => {
                            console.log("Link mouseenter event triggered");
                            // Get page name from data attribute
                            const pageName = link.getAttribute("data-page");
                            const projectName = link.getAttribute("data-project");

                            if (pageName) {
                                // Dispatch custom event for link preview show
                                const customEvent = new CustomEvent("linkPreviewShow", {
                                    detail: { pageName, projectName, element: link },
                                });
                                document.dispatchEvent(customEvent);
                            }
                        });

                        // Add mouseleave event listener
                        link.addEventListener("mouseleave", () => {
                            console.log("Link mouseleave event triggered");
                            // Dispatch custom event for link preview hide
                            const customEvent = new CustomEvent("linkPreviewHide");
                            document.dispatchEvent(customEvent);
                        });

                        // Set flag indicating listeners are set
                        link.setAttribute("data-link-listeners", "true");
                    }
                });

                return links.length;
            };

            // Set event listeners on links
            const linksWithListeners = setupLinkEventListeners();

            // Check if MutationObserver exists
            const hasMutationObserver = !!window.__linkPreviewMutationObserver;

            // Create MutationObserver if not exists
            if (!hasMutationObserver) {
                // Create MutationObserver
                const observer = new MutationObserver(mutations => {
                    let newLinksFound = false;

                    mutations.forEach(mutation => {
                        if (mutation.type === "childList" && mutation.addedNodes.length > 0) {
                            mutation.addedNodes.forEach(node => {
                                if (node.nodeType === Node.ELEMENT_NODE) {
                                    const element = node as Element;

                                    // Check if added element itself is internal link
                                    if (element.classList && element.classList.contains("internal-link")) {
                                        newLinksFound = true;
                                    }

                                    // Search for internal links within added element
                                    const links = element.querySelectorAll(".internal-link");
                                    if (links.length > 0) {
                                        newLinksFound = true;
                                    }
                                }
                            });
                        }
                    });

                    if (newLinksFound) {
                        console.log("New internal links found, setting up event listeners");
                        setupLinkEventListeners();
                    }
                });

                // Start observation
                observer.observe(document.body, {
                    childList: true,
                    subtree: true,
                    attributes: true,
                    attributeFilter: ["class"],
                });

                // Save to global variable
                window.__linkPreviewMutationObserver = observer;
            }

            return {
                itemsCount: items.length,
                linksFound,
                linksProcessed,
                linksWithListeners,
                hasMutationObserver,
            };
        });

        console.log(`Force render internal links result:`, result);

        // Wait for links to be processed
        await page.waitForTimeout(1000);
    }
}

// Extend global type definition
declare global {
    interface Window {
        __linkPreviewMutationObserver?: MutationObserver;
        __testShowLinkPreview?: (pageName: string, projectName?: string, pageExists?: boolean) => HTMLElement;
    }
}

/**
 * Polling Test Helper
 *
 * Utility to identify unnecessary polling using PollingMonitor in E2E tests
 */

import type { Page } from "@playwright/test";

export interface PollingTestResult {
    testName: string;
    withPolling: {
        passed: boolean;
        duration: number;
        error?: string;
    };
    withoutPolling: {
        passed: boolean;
        duration: number;
        error?: string;
    };
    pollingPattern: RegExp;
    isRemovable: boolean;
}

/**
 * Initialize Polling Monitor
 */
export async function initPollingMonitor(page: Page) {
    await page.addInitScript(() => {
        // Inline pollingMonitor.ts content
        class PollingMonitor {
            private calls: Map<number, any> = new Map();
            private nextId = 1;
            private enabled = false;
            private originalSetInterval: any;
            private originalSetTimeout: any;
            private disablePatterns: RegExp[] = [];

            constructor() {
                this.originalSetInterval = window.setInterval.bind(window);
                this.originalSetTimeout = window.setTimeout.bind(window);
            }

            start() {
                if (this.enabled) return;
                this.enabled = true;

                window.setInterval = (callback: any, delay?: number, ...args: any[]): any => {
                    const stack = new Error().stack || "";
                    const id = this.nextId++;
                    const disabled = this.disablePatterns.some(p => p.test(stack));

                    this.calls.set(id, {
                        id,
                        type: "setInterval",
                        delay,
                        stack,
                        createdAt: Date.now(),
                        executionCount: 0,
                        disabled,
                    });

                    if (disabled) {
                        console.log(`[PollingMonitor] Disabled setInterval (id=${id}, delay=${delay}ms)`);
                        return id;
                    }

                    const wrappedCallback = (...callbackArgs: any[]) => {
                        const call = this.calls.get(id);
                        if (call) {
                            call.executionCount++;
                            call.lastExecutedAt = Date.now();
                        }
                        return callback(...callbackArgs);
                    };

                    return this.originalSetInterval(wrappedCallback, delay, ...args);
                };

                window.setTimeout = ((callback: any, delay?: number, ...args: any[]): any => {
                    const stack = new Error().stack || "";
                    const id = this.nextId++;
                    const disabled = this.disablePatterns.some(p => p.test(stack));

                    this.calls.set(id, {
                        id,
                        type: "setTimeout",
                        delay,
                        stack,
                        createdAt: Date.now(),
                        executionCount: 0,
                        disabled,
                    });

                    if (disabled) {
                        console.log(`[PollingMonitor] Disabled setTimeout (id=${id}, delay=${delay}ms)`);
                        return id;
                    }

                    const wrappedCallback = (...callbackArgs: any[]) => {
                        const call = this.calls.get(id);
                        if (call) {
                            call.executionCount++;
                            call.lastExecutedAt = Date.now();
                        }
                        this.calls.delete(id);
                        return callback(...callbackArgs);
                    };

                    return this.originalSetTimeout(wrappedCallback, delay, ...args);
                }) as unknown as typeof window.setTimeout;
            }

            addDisablePattern(pattern: RegExp) {
                this.disablePatterns.push(pattern);
            }

            clearDisablePatterns() {
                this.disablePatterns = [];
            }

            getStats() {
                const calls = Array.from(this.calls.values());
                return {
                    totalCalls: calls.length,
                    activeCalls: calls.filter(c => !c.disabled).length,
                    disabledCalls: calls.filter(c => c.disabled).length,
                    calls: calls,
                };
            }

            reset() {
                this.calls.clear();
                this.nextId = 1;
            }
        }

        (window as any).__pollingMonitor = new PollingMonitor();
    });
}

/**
 * Start Polling Monitor
 */
export async function startPollingMonitor(page: Page) {
    await page.evaluate(() => {
        (window as any).__pollingMonitor?.start();
    });
}

/**
 * Get Polling Stats
 */
export async function getPollingStats(page: Page) {
    return await page.evaluate(() => {
        return (window as any).__pollingMonitor?.getStats();
    });
}

/**
 * Disable polling matching a specific pattern
 */
export async function disablePollingPattern(page: Page, pattern: RegExp) {
    await page.evaluate((patternStr) => {
        const regex = new RegExp(patternStr);
        (window as any).__pollingMonitor?.addDisablePattern(regex);
    }, pattern.source);
}

/**
 * Clear disable patterns
 */
export async function clearDisablePatterns(page: Page) {
    await page.evaluate(() => {
        (window as any).__pollingMonitor?.clearDisablePatterns();
    });
}

/**
 * Reset Polling Monitor
 */
export async function resetPollingMonitor(page: Page) {
    await page.evaluate(() => {
        (window as any).__pollingMonitor?.reset();
    });
}

/**
 * Run test with specific polling disabled
 */
export async function testWithoutPolling(
    page: Page,
    testName: string,
    pollingPattern: RegExp,
    testFn: () => Promise<void>,
): Promise<PollingTestResult> {
    const result: PollingTestResult = {
        testName,
        withPolling: { passed: false, duration: 0 },
        withoutPolling: { passed: false, duration: 0 },
        pollingPattern,
        isRemovable: false,
    };

    // 1. Test WITH polling
    console.log(`\n[${testName}] Testing WITH polling...`);
    await clearDisablePatterns(page);
    await resetPollingMonitor(page);

    const startWith = Date.now();
    try {
        await testFn();
        result.withPolling.passed = true;
        result.withPolling.duration = Date.now() - startWith;
        console.log(`  ✓ Passed (${result.withPolling.duration}ms)`);
    } catch (error: any) {
        result.withPolling.passed = false;
        result.withPolling.duration = Date.now() - startWith;
        result.withPolling.error = error.message;
        console.log(`  ✗ Failed: ${error.message}`);
    }

    // 2. Test WITHOUT polling
    console.log(`[${testName}] Testing WITHOUT polling...`);
    await page.reload();
    await disablePollingPattern(page, pollingPattern);
    await resetPollingMonitor(page);

    const startWithout = Date.now();
    try {
        await testFn();
        result.withoutPolling.passed = true;
        result.withoutPolling.duration = Date.now() - startWithout;
        console.log(`  ✓ Passed (${result.withoutPolling.duration}ms)`);
    } catch (error: any) {
        result.withoutPolling.passed = false;
        result.withoutPolling.duration = Date.now() - startWithout;
        result.withoutPolling.error = error.message;
        console.log(`  ✗ Failed: ${error.message}`);
    }

    // 3. Determine Result
    result.isRemovable = result.withPolling.passed && result.withoutPolling.passed;

    if (result.isRemovable) {
        console.log(`[${testName}] ✓ This polling is removable`);
    } else if (!result.withPolling.passed) {
        console.log(`[${testName}] ⚠ The test itself failed`);
    } else {
        console.log(`[${testName}] ✗ This polling is necessary`);
    }

    return result;
}

/**
 * Generate Report
 */
export function generatePollingTestReport(results: PollingTestResult[]): string {
    let report = "# Polling Removability Test Report\n\n";
    report += `Generated at: ${new Date().toISOString()}\n\n`;
    report += `## Overview\n\n`;
    report += `- Tests Executed: ${results.length}\n`;
    report += `- Removable: ${results.filter(r => r.isRemovable).length}\n`;
    report += `- Necessary: ${results.filter(r => !r.isRemovable).length}\n\n`;

    const removable = results.filter(r => r.isRemovable);
    if (removable.length > 0) {
        report += `## Removable Polling\n\n`;
        for (const result of removable) {
            report += `### ${result.testName}\n\n`;
            report += `- **Pattern**: \`${result.pollingPattern.source}\`\n`;
            report += `- **With Polling**: ${result.withPolling.duration}ms\n`;
            report += `- **Without Polling**: ${result.withoutPolling.duration}ms\n`;
            report += `- **Recommendation**: This polling can be safely removed\n\n`;
        }
    }

    const necessary = results.filter(r => !r.isRemovable);
    if (necessary.length > 0) {
        report += `## Necessary Polling\n\n`;
        for (const result of necessary) {
            report += `### ${result.testName}\n\n`;
            report += `- **Pattern**: \`${result.pollingPattern.source}\`\n`;
            report += `- **With Polling**: ${
                result.withPolling.passed ? "✓" : "✗"
            } (${result.withPolling.duration}ms)\n`;
            report += `- **Without Polling**: ${
                result.withoutPolling.passed ? "✓" : "✗"
            } (${result.withoutPolling.duration}ms)\n`;
            if (result.withoutPolling.error) {
                report += `- **Error**: ${result.withoutPolling.error}\n`;
            }
            report += `- **Recommendation**: This polling is necessary\n\n`;
        }
    }

    return report;
}

