            return false;
        }
    }

    /**
     * Find outliner elements
     */
    public static async findOutlinerElements(page: Page): Promise<{
        found: boolean;
        elements: string[];
    }> {
        try {
            const elements: string[] = [];

            // Find common outliner elements
            const selectors = [
                ".outliner-item",
                ".item-content",
                '[data-testid="outliner"]',
                '[data-testid="item"]',
                ".outliner",
                ".item",
                "main",
                "#app",
            ];

            for (const selector of selectors) {
                const count = await page.locator(selector).count();
                if (count > 0) {
                    elements.push(`${selector}: ${count} elements`);
                }
            }

            console.log("TestHelper: Found outliner elements:", elements);

            return {
                found: elements.length > 0,
                elements,
            };
        } catch (error) {
            console.error("TestHelper: Error finding outliner elements:", error);
            return {
                found: false,
                elements: [],
            };
        }
    }

    /**
     * Monitor JavaScript errors
     */
    public static setupErrorMonitoring(page: Page): string[] {
        const errors: string[] = [];

        page.on("console", msg => {
            if (msg.type() === "error") {
                errors.push(msg.text());
                console.log("TestHelper: JavaScript error detected:", msg.text());
            }
        });

        page.on("pageerror", error => {
            errors.push(error.message);
            console.log("TestHelper: Page error detected:", error.message);
        });

        return errors;
    }

    /**
     * Monitor network requests
     */
    public static setupNetworkMonitoring(page: Page): {
        requests: any[];
        responses: any[];
    } {
        const requests: any[] = [];
        const responses: any[] = [];

        page.on("request", request => {
            requests.push({
                url: request.url(),
                method: request.method(),
                timestamp: Date.now(),
            });
        });

        page.on("response", response => {
            responses.push({
                url: response.url(),
                status: response.status(),
                timestamp: Date.now(),
            });
        });

        return { requests, responses };
    }
}

